const platformName = "startupjobs";

for (const item of $input.all()) {
  item.json.source = platformName;
}

return $input.all();

const today = new Date().getDay();
let publishedAtString = "r86400"; 

if (today === 1) { 
  publishedAtString = "r604800"; 
}

return {
  publishedAtString
};

for (const item of $input.all()) {
  const jd = item.json.description_text;

  const japaneseRegex = /[\u3040-\u309F\u30A0-\u30FF]/;

  item.json.isJapanese = japaneseRegex.test(jd);
}

return $input.all();
